mapper.select:
SELECT * FROM t_salary_record


        AND `year_month` = #{yearMonth}


        AND emp_no = #{empNo}


        AND emp_name LIKE CONCAT('%', #{realName}, '%')


        AND dept_id = #{deptId}


        AND calc_status = #{calcStatus}


        AND calc_status <> 1


        AND manager_id = #{managerId}


        AND emp_no <> #{excludeEmpNo}


ORDER BY `year_month` DESC, create_time DESC

SELECT * FROM t_salary_record
WHERE emp_id    = #{empId}
  AND `year_month` = #{yearMonth}
LIMIT 1

SELECT trend.month, trend.total FROM ( SELECT `year_month` AS month, SUM(net_salary) AS total FROM t_salary_record
AND `year_month` <= #{anchorYearMonth}
GROUP BY `year_month` ORDER BY `year_month` DESC LIMIT 12 ) trend ORDER BY trend.month ASC

SELECT
    SUM(base_salary) as baseSalary,
    SUM(perf_bonus) as perfBonus,
    SUM(overtime_pay) as overtimePay,
    SUM(allowance) as allowance
FROM t_salary_record

    AND `year_month` = #{yearMonth}

        AND manager_no = #{managerNo}


        AND emp_no <> #{excludeEmpNo}

SELECT dept_name as dept_name, AVG(net_salary) as avg_salary FROM t_salary_record
AND `year_month` = #{yearMonth}
GROUP BY dept_name ORDER BY avg_salary DESC
